INSERT INTO flora_species (slug, name, scientific_name, description, plant_type, family_name, habitat, elevation_range, is_endemic, is_medicinal, medicinal_uses, conservation_status, is_featured, fun_facts) VALUES

-- Trees (15)
('sal-tree', 'Sal Tree', 'Shorea robusta', 'Dominant tree of Nepal''s Terai forests. Important for timber and traditional medicine.', 'Tree', 'Dipterocarpaceae', 'Tropical and subtropical forests', '100-1000m', false, true, 'Anti-inflammatory, treatment of skin diseases, timber', 'LEAST_CONCERN', true, 'Sal trees can live for 200+ years and grow up to 30 meters tall.'),
('chir-pine', 'Chir Pine', 'Pinus roxburghii', 'Widespread pine species in Nepal''s mid-hills. Important for resin production.', 'Tree', 'Pinaceae', 'Subtropical and temperate forests', '500-2000m', false, true, 'Resin for turpentine, timber, erosion control', 'LEAST_CONCERN', false, 'Chir pine resin is processed into turpentine oil and colophony.'),
('oak-tree', 'Indian Oak (Ban Oak)', 'Quercus leucotrichophora', 'Important broadleaf tree in Nepal''s temperate forests. Supports diverse epiphytes.', 'Tree', 'Fagaceae', 'Temperate forests', '1500-3000m', false, false, 'Timber, firewood, supports epiphytic orchids', 'LEAST_CONCERN', false, 'Oak forests support over 100 species of epiphytic orchids in Nepal.'),
('rhododendron-tree', 'Tree Rhododendron', 'Rhododendron arboreum', 'Nepal''s national flower (laliguras). Stunning red flowers bloom in March-April.', 'Tree', 'Ericaceae', 'Temperate and subalpine forests', '2000-3800m', false, false, 'Ornamental, traditional medicine', 'LEAST_CONCERN', true, 'Rhododendron is Nepal''s national flower. The species arboreum can grow into a tree up to 20m tall.'),
('bamboo', 'Nepal Bamboo', 'Dendrocalamus hamiltonii', 'Large bamboo species important for construction and crafts.', 'Tree', 'Poaceae', 'Subtropical forests, riverine areas', '200-1500m', false, true, 'Construction, crafts, food, paper', 'LEAST_CONCERN', false, 'Some bamboo species can grow up to 91 cm in a single day.'),
('chir-chitawan', 'Chir Pine', 'Pinus longifolia', 'Long-leaved pine important for resin and timber in Terai.', 'Tree', 'Pinaceae', 'Subtropical forests', '300-1800m', false, true, 'Resin, timber, erosion control', 'LEAST_CONCERN', false, 'Chir pine forests cover large areas of Nepal''s mid-hills.'),
('alder', 'Himalayan Alder', 'Alnus nepalensis', 'Important nitrogen-fixing tree. Pioneer species in disturbed areas.', 'Tree', 'Betulaceae', 'Temperate forests, stream banks', '1200-3500m', false, false, 'Nitrogen fixation, soil improvement, firewood', 'LEAST_CONCERN', false, 'Himalayan alder fixes atmospheric nitrogen, enriching the soil for other plants.'),
('birch', 'Himalayan Birch (Bhojpatra)', 'Betula utilis', 'Bark used for writing ancient manuscripts. Found at high altitudes.', 'Tree', 'Betulaceae', 'Subalpine forests', '3000-4200m', false, true, 'Writing material, traditional medicine', 'LEAST_CONCERN', true, 'Ancient Hindu and Buddhist scriptures were written on birch bark manuscripts.'),
('spruce', 'Blue Pine', 'Pinus wallichiana', 'Elegant pine with long needles. Found in western Nepal mountains.', 'Tree', 'Pinaceae', 'Temperate and subalpine forests', '1800-3500m', false, false, 'Timber, resin, ornamental', 'LEAST_CONCERN', false, 'Blue pine forests are important habitats for Himalayan monal pheasants.'),
('cedar', 'Himalayan Cedar (Deodar)', 'Cedrus deodara', 'Sacred timber tree. Deodar means ''wood of the gods'' in Sanskrit.', 'Tree', 'Pinaceae', 'Temperate forests', '1500-3000m', false, true, 'Premium timber, essential oil, anti-fungal', 'NEAR_THREATENED', true, 'Deodar is considered sacred and is used in temple construction.'),
('mango-wild', 'Wild Mango', 'Mangifera indica', 'Wild ancestor of cultivated mango. Found in Nepal''s Terai forests.', 'Tree', 'Anacardiaceae', 'Tropical forests', '100-500m', false, false, 'Fruit, timber, traditional medicine', 'LEAST_CONCERN', false, 'Wild mango trees can live for over 300 years.'),
('jamun', 'Jamun (Black Plum)', 'Syzygium cumini', 'Fruit tree with medicinal properties. Found in Nepal''s lowlands.', 'Tree', 'Myrtaceae', 'Tropical and subtropical forests', '200-1500m', false, true, 'Diabetes treatment, fruit, timber', 'LEAST_CONCERN', false, 'Jamun seeds are traditionally used to treat diabetes in Ayurveda.'),
('peepal', 'Peepal Tree', 'Ficus religiosa', 'Sacred fig tree. Considered holy in Hinduism and Buddhism.', 'Tree', 'Moraceae', 'Tropical to subtropical areas', '100-1500m', false, true, 'Religious significance, traditional medicine', 'LEAST_CONCERN', true, 'The peepal tree under which Buddha attained enlightenment is in Bodh Gaya, India.'),
('banyan', 'Banyan Tree', 'Ficus benghalensis', 'Massive fig tree with aerial roots. Sacred in Hinduism.', 'Tree', 'Moraceae', 'Tropical and subtropical areas', '100-1000m', false, true, 'Religious significance, shade, traditional medicine', 'LEAST_CONCERN', true, 'The Great Banyan in India covers 14,500 square meters.'),
('salix', 'Himalayan Willow', 'Salix denticulata', 'Water-loving tree found along rivers and streams.', 'Tree', 'Salicaceae', 'Riversides, wetlands', '1000-3000m', false, true, 'Basket making, traditional medicine', 'LEAST_CONCERN', false, 'Willow bark contains salicin, the precursor to aspirin.'),

-- Shrubs and Others (15)
('rhododendron-laliguras', 'Laliguras (Red Rhododendron)', 'Rhododendron arboreum', 'Nepal''s national flower. Spectacular red blooms in spring forests.', 'Shrub', 'Ericaceae', 'Temperate and subalpine forests', '1800-3800m', false, false, 'Ornamental, cultural significance', 'LEAST_CONCERN', true, 'Laliguras blooms in March-April, turning entire hillsides red.'),
('hippo-rose', 'Himalayan Rose', 'Rosa sericea', 'Wild rose with stunning golden thorns found in mountain forests.', 'Shrub', 'Rosaceae', 'Temperate and subalpine forests', '2000-4000m', false, true, 'Traditional medicine, ornamental', 'LEAST_CONCERN', false, 'Himalayan roses have unique four-petaled flowers unlike most roses which have five.'),
('tea-plant', 'Himalayan Tea', 'Camellia sinensis', 'Tea plant grown in Nepal''s eastern hills. Premium organic tea production.', 'Shrub', 'Theaceae', 'Subtropical forests, plantations', '600-2000m', false, true, 'Beverage, antioxidant', 'LEAST_CONCERN', false, 'Nepal''s Ilam tea is considered among the finest in the world.'),
('turmeric', 'Himalayan Turmeric', 'Curcuma longa', 'Golden spice plant used in cooking and Ayurvedic medicine.', 'Shrub', 'Zingiberaceae', 'Tropical and subtropical forests', '200-1500m', false, true, 'Anti-inflammatory, cooking, Ayurvedic medicine', 'LEAST_CONCERN', false, 'Turmeric has been used in Nepali medicine for over 4000 years.'),
('chirata', 'Chirata', 'Swertia chirayita', 'Bitter medicinal herb used in traditional Nepali medicine.', 'Herb', 'Gentianaceae', 'Subalpine meadows', '1200-3500m', false, true, 'Fever treatment, digestive aid, liver tonic', 'VULNERABLE', true, 'Chirata is one of Nepal''s most exported medicinal plants.'),
('yarsagumba', 'Yarsagumba (Cordyceps)', 'Ophiocordyceps sinensis', 'Caterpillar fungus worth more than gold. Found in alpine meadows.', 'Fungus', 'Ophiocordycipitaceae', 'Alpine meadows above 4000m', '3500-5500m', false, true, 'Energy booster, traditional medicine, aphrodisiac', 'VULNERABLE', true, 'Yarsagumba can fetch up to $50,000/kg and is Nepal''s most expensive natural product.'),
('jatamansi', 'Jatamansi (Spikenard)', 'Nardostachys jatamansi', 'Aromatic herb used in traditional medicine and perfumery.', 'Herb', 'Valerianaceae', 'Alpine meadows', '3000-5000m', false, true, 'Sedative, anti-anxiety, hair growth', 'ENDANGERED', true, 'Jatamansi is mentioned in ancient Egyptian texts as a precious perfume ingredient.'),
('pandanus', 'Pandanus (Taal)', 'Pandanus nepalensis', 'Screw pine found in Nepal''s lowlands. Used for weaving.', 'Shrub', 'Pandanaceae', 'Tropical lowlands, wetlands', '100-500m', false, true, 'Weaving, traditional medicine', 'LEAST_CONCERN', false, 'Pandanus leaves are used to make mats, baskets, and thatched roofs.'),
('bay-leaf', 'Nepali Bay Leaf', 'Cinnamomum tamala', 'Aromatic spice leaf used in Nepali cooking.', 'Tree', 'Lauraceae', 'Subtropical forests', '800-2000m', false, true, 'Cooking spice, traditional medicine', 'LEAST_CONCERN', false, 'Nepali bay leaves are different from European bay leaves.'),
('timur', 'Timur (Sichuan Pepper)', 'Zanthoxylum armatum', 'Thorny shrub with aromatic berries used as spice.', 'Shrub', 'Rutaceae', 'Subtropical and temperate forests', '500-2500m', false, true, 'Spice, traditional medicine, flavoring', 'LEAST_CONCERN', false, 'Timur is the key ingredient in Nepali momo achar (dipping sauce).'),
('mehndi', 'Mehndi (Henna)', 'Lawsonia inermis', 'Plant used for traditional body art and hair coloring.', 'Shrub', 'Lythraceae', 'Tropical areas', '100-500m', false, true, 'Body art, hair coloring, traditional medicine', 'LEAST_CONCERN', false, 'Henna has been used for body art for over 5000 years.'),
('tulsi', 'Holy Basil (Tulsi)', 'Ocimum tenuiflorum', 'Sacred plant in Hinduism. Used in Ayurvedic medicine.', 'Herb', 'Lamiaceae', 'Gardens, temples, tropical areas', '100-1500m', false, true, 'Religious, cough treatment, stress relief', 'LEAST_CONCERN', true, 'Tulsi is considered an incarnation of goddess Lakshmi in Hinduism.'),
('neem', 'Neem', 'Azadirachta indica', 'Miracle tree with numerous medicinal and pesticidal properties.', 'Tree', 'Meliaceae', 'Tropical and subtropical areas', '100-800m', false, true, 'Pesticide, dental care, traditional medicine', 'LEAST_CONCERN', false, 'Neem is used in over 75% of Nepali traditional medicines.'),
('amlakhi', 'Indian Gooseberry (Amla)', 'Phyllanthus emblica', 'Sour fruit tree rich in vitamin C. Important Ayurvedic herb.', 'Tree', 'Phyllanthaceae', 'Subtropical forests', '200-1500m', false, true, 'Vitamin C, hair care, digestive aid', 'LEAST_CONCERN', false, 'Amla contains 20x more vitamin C than oranges.'),
('saag', 'Nepali Spinach', 'Houttuynia cordata', 'Herb used as vegetable and medicine in Nepal.', 'Herb', 'Saururaceae', 'Subtropical forests, wet areas', '500-2500m', false, true, 'Food, traditional medicine, antibiotic', 'LEAST_CONCERN', false, 'Houttuynia is also known as ''fish mint'' for its fish-like smell.');

