-- LAKES (30 records)
-- ============================================================
INSERT INTO lakes (slug, name, description, lake_type, district, province, elevation_m, area_sq_km, max_depth_m, length_km, width_km, notable_features, is_featured) VALUES

('rara-lake', 'Rara Lake', 'Largest lake in Nepal. Crystal-clear water surrounded by pristine forests in remote Mugu district.', 'NATURAL', 'Mugu', 'Karnali', 2990, 10.4, 16, 5.1, 3.2, 'Nepal''s largest lake, Rara National Park, pristine forests, remote wilderness', true),
('phoksundo-lake', 'Phoksundo Lake', 'Deepest lake in Nepal at 145 meters. Stunning turquoise water in Dolpa district.', 'TECTONIC', 'Dolpa', 'Karnali', 3612, 4.94, 145, 5.15, 0.8, 'Nepal''s deepest lake, turquoise color, Phoksundo National Park, Bonpo monastery', true),
